using Microsoft.Extensions.Logging;
namespace Valora.Application.Certificates;
public sealed class CertificateService(ILogger<CertificateService> logger) { public object Plan(Guid responseId, string format) { logger.LogInformation("Certificate plan requested. ResponseId={ResponseId} Format={Format}", responseId, format); return new { product="Valora Pulse™", issuer="Valora Group", title="Certificado de Diagnóstico", participant="participante", maskedEmail="p***@email.com", survey="Diagnóstico gratuito Valora Insight", completedAt=DateTimeOffset.UtcNow, totalScore="pontuação total", maturityLevel="nível de maturidade", summary="resumo curto do nível de maturidade", responseId, format, validationCode = $"VALORA-{responseId:N}"[..19], validationLink=$"/certificates/validate/VALORA-{responseId:N}", authenticity="Documento autêntico validável pelo código público.", privacy="LGPD/privacidade: dados mínimos e e-mail mascarado.", cta="Fale com a Valora para análise completa.", status = "planned" }; } }
